- **Install Dependencies**: `npm install @nestjs/bull bull`
- **Register Bull Module**: 
  ```typescript
  import { BullModule } from '@nestjs/bull';

  @Module({
    imports: [BullModule.forRoot({ redis: { host: 'localhost', port: 6379 } })],
  })
  export class AppModule {}
  ```
- **Create a Queue**:
  ```typescript
  import { Module } from '@nestjs/common';
  import { BullModule } from '@nestjs/bull';

  @Module({
    imports: [BullModule.registerQueue({ name: 'myqueue' })],
  })
  export class MyQueueModule {}
  ```
- **Define a Processor (Worker)**:
  ```typescript
  import { Processor, Process } from '@nestjs/bull';
  import { Job } from 'bull';

  @Processor('myqueue')
  export class MyQueueProcessor {
    @Process()
    async handle(job: Job) {
      console.log(`Processing job ${job.id}`);
    }
  }
  ```
- **Add Jobs to Queue**:
  ```typescript
  import { Injectable } from '@nestjs/common';
  import { InjectQueue } from '@nestjs/bull';
  import { Queue } from 'bull';

  @Injectable()
  export class MyQueueService {
    constructor(@InjectQueue('myqueue') private readonly myQueue: Queue) {}

    async addJob(data: any) {
      await this.myQueue.add('jobName', data);
    }
  }
  ```
- **Latest Versions**: NestJS v10, Bull v3
- **Key Config Options**:
  - `redis`: Configuration for Redis connection.
  - `name`: Name of the queue.
  - `process`: Method to handle jobs in the queue.

